# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System;
using UnityEngine;

public class Player : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health <= 0)
        {
            Die();
        }
    }

    private void Die()
    {
        // Handle player death
        Debug.Log("Player died.");
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Currency added. Current total: " + currency);
    }
}

public class Shop : MonoBehaviour
{
    public Player player;

    public bool PurchaseItem(int price)
    {
        if (player.currency >= price)
        {
            player.currency -= price;
            Debug.Log("Item purchased.");
            return true;
        }
        else
        {
            Debug.Log("Not enough currency.");
            return false;
        }
    }

    public int CalculatePrice(int basePrice, int multiplier)
    {
        return basePrice * multiplier;
    }
}

public class GameManager : MonoBehaviour
{
    public Player player;
    public Shop shop;

    void Start()
    {
        shop.player = player;
    }

    public void ApplyDamageToPlayer(int damage)
    {
        player.TakeDamage(damage);
    }
    
    public void TryPurchaseItem(int basePrice, int multiplier)
    {
        int price = shop.CalculatePrice(basePrice, multiplier);
        shop.PurchaseItem(price);
    }
}